   124→
   125→    if (!question) {
   126→      return res.status(400).json({ error: 'Invalid question index' });
   127→    }
   128→
   129→    // Analyze response with AI
   130→    const analysis = await analyzeInterviewResponse(
   131→      question.question,
   132→      response_text,
   133→      question.key_points || [],
   134→      { subscriptionId: req.user.stripe_subscription_id }
   135→    );
   136→
   137→    // Update responses array
   138→    const responses = interviewData.responses || [];
   139→    responses[question_index] = {
   140→      question_index,
   141→      response_text,
   142→      video_url,
   143→      analysis,
   144→      submitted_at: new Date().toISOString()
   145→    };
   146→
   147→    // Update video URLs if provided
   148→    const videoUrls = interviewData.video_urls || [];
   149→    if (video_url) {
   150→      videoUrls[question_index] = video_url;
   151→    }
   152→
   153→    // Update responses - use updated_at if column exists, fallback gracefully
   154→    try {
   155→      await pool.query(
   156→        `UPDATE interviews SET responses = $1, video_urls = $2, updated_at = NOW()
   157→         WHERE id = $3`,
   158→        [JSON.stringify(responses), JSON.stringify(videoUrls), req.params.id]
   159→      );
   160→    } catch (updateErr) {
   161→      // Fallback if updated_at column doesn't exist yet (pre-migration)
   162→      if (updateErr.message && updateErr.message.includes('updated_at')) {
   163→        console.warn('updated_at column missing, updating without it');
   164→        await pool.query(
   165→          `UPDATE interviews SET responses = $1, video_urls = $2
   166→           WHERE id = $3`,
   167→          [JSON.stringify(responses), JSON.stringify(videoUrls), req.params.id]
   168→        );
   169→      } else {
   170→        throw updateErr;
   171→      }
   172→    }
