   186→// Upload and parse resume
   187→router.post('/resume/upload', authMiddleware, upload.single('resume'), async (req, res) => {
   188→  try {
   189→    if (!req.file) {
   190→      return res.status(400).json({ error: 'No file uploaded' });
   191→    }
   192→
   193→    // Upload to R2
   194→    const formData = new FormData();
   195→    formData.append('file', req.file.buffer, {
   196→      filename: req.file.originalname,
   197→      contentType: req.file.mimetype
   198→    });
   199→
   200→    const uploadRes = await fetch('https://polsia.com/api/proxy/r2/upload', {
   201→      method: 'POST',
   202→      headers: {
   203→        'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
   204→        ...formData.getHeaders()
   205→      },
   206→      body: formData
   207→    });
   208→
   209→    const uploadResult = await uploadRes.json();
   210→    if (!uploadResult.success) {
   211→      throw new Error(uploadResult.error?.message || 'Upload failed');
   212→    }
   213→
   214→    // Save parsed resume record
   215→    const resumeRecord = await pool.query(`
   216→      INSERT INTO parsed_resumes (user_id, original_filename, file_url, parsing_status)
   217→      VALUES ($1, $2, $3, 'processing')
   218→      RETURNING id
   219→    `, [req.user.id, req.file.originalname, uploadResult.file.url]);
   220→
   221→    // Update profile with resume URL
   222→    await pool.query(`
   223→      INSERT INTO candidate_profiles (user_id, resume_url)
   224→      VALUES ($1, $2)
   225→      ON CONFLICT (user_id) DO UPDATE SET resume_url = $2, updated_at = NOW()
   226→    `, [req.user.id, uploadResult.file.url]);
   227→
   228→    // Try to extract text from the resume buffer
   229→    // For PDFs/DOCX, binary-to-string won't produce useful text
   230→    // We attempt extraction but gracefully handle failure
   231→    let parsedData = null;
   232→    try {
   233→      const resumeText = req.file.buffer.toString('utf-8');
   234→
   235→      // Check if the extracted text looks like actual text (not binary garbage)
   236→      // PDF files start with %PDF, DOCX files are ZIP archives starting with PK
   237→      const isProbablyText = resumeText.length > 0
   238→        && !resumeText.startsWith('%PDF')
   239→        && !resumeText.startsWith('PK')
   240→        && /[a-zA-Z]{3,}/.test(resumeText.substring(0, 500));
   241→
   242→      if (isProbablyText && resumeText.trim().length > 50) {
   243→        // Get user's subscription for tracking
   244→        const user = await pool.query('SELECT stripe_subscription_id FROM users WHERE id = $1', [req.user.id]);
   245→        const subscriptionId = user.rows[0]?.stripe_subscription_id;
   246→
   247→        // Parse with AI, with a 30-second timeout
   248→        const parsePromise = parseResume(resumeText.substring(0, 15000), { subscriptionId });
   249→        const timeoutPromise = new Promise((_, reject) =>
   250→          setTimeout(() => reject(new Error('AI parsing timeout')), 30000)
   251→        );
   252→
   253→        parsedData = await Promise.race([parsePromise, timeoutPromise]);
   254→
   255→        // Update the record with parsed data
   256→        await pool.query(`
   257→          UPDATE parsed_resumes
   258→          SET parsed_data = $1, parsing_status = 'completed', parsed_at = NOW()
   259→          WHERE id = $2
   260→        `, [JSON.stringify(parsedData), resumeRecord.rows[0].id]);
   261→      } else {
   262→        console.log('Resume appears to be binary format (PDF/DOCX) - skipping text parsing');
   263→        await pool.query(`
   264→          UPDATE parsed_resumes
   265→          SET parsing_status = 'uploaded', parsed_at = NOW()
   266→          WHERE id = $1
   267→        `, [resumeRecord.rows[0].id]);
   268→      }
   269→    } catch (parseErr) {
   270→      console.error('Resume parsing failed (non-fatal):', parseErr.message);
   271→      await pool.query(`
   272→        UPDATE parsed_resumes
   273→        SET parsing_status = 'failed', parsed_at = NOW()
   274→        WHERE id = $1
   275→      `, [resumeRecord.rows[0].id]);
   276→    }
   277→
   278→    res.json({
   279→      success: true,
   280→      resume_url: uploadResult.file.url,
   281→      parsed_data: parsedData,
   282→      resume_id: resumeRecord.rows[0].id
   283→    });
   284→  } catch (err) {
   285→    console.error('Resume upload error:', err);
   286→    res.status(500).json({ error: 'Failed to upload resume' });
   287→  }
